// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "CNC controller measures motor input current I_M"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor position encoder provides angular position r_M of the motor shaft"
    DTDFVocab:producedData MotorPositionDataTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder behind the gearbox provides output angle r_out"
    DTDFVocab:producedData GearboxPositionDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

// C10: Data (measured and simulated)
instance MeasuredCurrentData : DTDFVocab:Data [
    base:desc "Measured motor current I_M trace streamed from the robot"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTEnabler
]

instance MeasuredMotorPositionData : DTDFVocab:Data [
    base:desc "Measured motor angular position r_M trace"
    DTDFVocab:fromData MotorPositionDataTransmitted
    DTDFVocab:inputTo MQTTEnabler
]

instance MeasuredGearboxPositionData : DTDFVocab:Data [
    base:desc "Measured gearbox output angle r_out trace"
    DTDFVocab:fromData GearboxPositionDataTransmitted
    DTDFVocab:inputTo MQTTEnabler
]

instance SimulatedMotorPositionData : DTDFVocab:Data [
    base:desc "Simulated motor position ˆr_M generated by Simulink friction models"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulatedGearboxPositionData : DTDFVocab:Data [
    base:desc "Simulated gearbox output position ˆr_out generated by Simulink friction models"
    DTDFVocab:inputTo SimulinkEnabler
]

// C10: Models
instance SysMLStructureModel : DTDFVocab:Model [
    base:desc "SysML model describing the structural hierarchy Axis, Motor, Gearbox and flow ports"
