]

instance SimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink environment executing friction models and generating simulated data"
    DTDFVocab:enables FrictionIdentificationService, FrictionParameterGenerationService
]

instance MQTTEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker for live streaming of sensor data to the digital twin"
    DTDFVocab:enables RealTimeVisualizationService
]

instance AASEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing model integration and metadata exposure"
    DTDFVocab:enables FrictionIdentificationService, RealTimeVisualizationService
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Custom visualization dashboard rendering real‑time data and friction insights"
    DTDFVocab:enables RealTimeVisualizationService, FrictionParameterGenerationService
]

// C6: Services
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous identification of static, kinetic and viscous friction using white‑box and black‑box models"
    DTDFVocab:provides DerivedFrictionParametersInsight
]

instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Real‑time visualization of measured and simulated torque, velocity and acceleration in the dashboard"
    DTDFVocab:provides PositioningErrorReductionInsight
]

instance FrictionParameterGenerationService : DTDFVocab:Service [
    base:desc "Generation of refined friction parameters for improving model‑based motion control"
    DTDFVocab:provides AdjustMotionControlAction
]

// C17: Insights
instance DerivedFrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Derives static, kinetic and viscous friction parameters from live data"
]

instance PositioningErrorReductionInsight : DTDFVocab:Insight [
    base:desc "Identifies reduction of positioning errors based on updated friction model"
]

// C17: Actions
instance AdjustMotionControlAction : DTDFVocab:Action [
    base:desc "Feeds refined friction parameters back to the robot controller to adjust motion control"
    DTDFVocab:IsAutomatic true
]

